package alerts

import "notification-svc/internal/notifiers"

type Handler struct {
	Email *notifiers.EmailNotifier
	Slack *notifiers.SlackNotifier
}

func (h *Handler) Handle(alert Alert) error {
	if err := h.Email.Notify(alert.Title, alert.Message); err != nil {
		return err
	}
	if alert.Severity == SeverityCritical && h.Slack != nil {
		msg := alert.Message + "\nSource: " + alert.Source
		return h.Slack.Notify(alert.Title, msg)
	}
	return nil
}
